CREATE TABLE modules (id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL, name VARCHAR(255) NOT NULL, type VARCHAR(255) NOT NULL, class VARCHAR(255) NOT NULL, description VARCHAR(255) NOT NULL, is_manage BOOLEAN NOT NULL, installed_at DATETIME NOT NULL);
CREATE TABLE bans (id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL, ip VARCHAR(255) NOT NULL, reason VARCHAR(255) NOT NULL, is_global BOOLEAN NOT NULL, staff_note VARCHAR(255) NOT NULL, created_at DATETIME NOT NULL, expires_at DATETIME NOT NULL, allow_read BOOLEAN NOT NULL, allow_appeal BOOLEAN NOT NULL, appeal_message VARCHAR(255) DEFAULT NULL, appeal_submitted_at DATETIME NOT NULL, appeal_is_approved BOOLEAN NOT NULL);
CREATE TABLE post_attachments (id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL, path VARCHAR(255) NOT NULL, file_name VARCHAR(255) NOT NULL, original_name VARCHAR(255) NOT NULL, md5_hash VARCHAR(255) NOT NULL, post_id INTEGER NOT NULL, CONSTRAINT FK_AB8470F94B89032C FOREIGN KEY (post_id) REFERENCES posts (id) NOT DEFERRABLE INITIALLY IMMEDIATE);
CREATE INDEX IDX_AB8470F94B89032C ON post_attachments (post_id);
CREATE TABLE sections (id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL, name VARCHAR(255) NOT NULL, is_hidden BOOLEAN NOT NULL, created_at DATETIME NOT NULL);
CREATE UNIQUE INDEX UNIQ_2B9643985E237E06 ON sections (name);
CREATE TABLE board_options (id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL, name VARCHAR(255) NOT NULL, value VARCHAR(255) DEFAULT NULL, board_id INTEGER DEFAULT NULL, CONSTRAINT FK_982BD288E7EC5785 FOREIGN KEY (board_id) REFERENCES boards (id) NOT DEFERRABLE INITIALLY IMMEDIATE);
CREATE INDEX IDX_982BD288E7EC5785 ON board_options (board_id);
CREATE TABLE posts (id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL, subject VARCHAR(255) DEFAULT NULL, message VARCHAR(255) NOT NULL, created_at DATETIME NOT NULL, locked_at DATETIME DEFAULT NULL, stickied_at DATETIME DEFAULT NULL, bumped_at DATETIME DEFAULT NULL, deletion_password VARCHAR(255) DEFAULT NULL, poster_name VARCHAR(255) DEFAULT NULL, poster_tripcode VARCHAR(255) DEFAULT NULL, poster_email VARCHAR(255) DEFAULT NULL, poster_ip VARCHAR(255) NOT NULL, board_id INTEGER NOT NULL, parent_id INTEGER DEFAULT NULL, CONSTRAINT FK_885DBAFAE7EC5785 FOREIGN KEY (board_id) REFERENCES boards (id) NOT DEFERRABLE INITIALLY IMMEDIATE, CONSTRAINT FK_885DBAFA727ACA70 FOREIGN KEY (parent_id) REFERENCES posts (id) NOT DEFERRABLE INITIALLY IMMEDIATE);
CREATE INDEX IDX_885DBAFAE7EC5785 ON posts (board_id);
CREATE INDEX IDX_885DBAFA727ACA70 ON posts (parent_id);
CREATE TABLE boards (id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL, name VARCHAR(255) NOT NULL, directory VARCHAR(255) NOT NULL, created_at DATETIME NOT NULL, section_id INTEGER DEFAULT NULL, CONSTRAINT FK_F3EE4D13D823E37A FOREIGN KEY (section_id) REFERENCES sections (id) NOT DEFERRABLE INITIALLY IMMEDIATE);
CREATE UNIQUE INDEX UNIQ_F3EE4D13467844DA ON boards (directory);
CREATE INDEX IDX_F3EE4D13D823E37A ON boards (section_id);
CREATE TABLE boards_attachment_types (board_id INTEGER NOT NULL, attachment_type_id INTEGER NOT NULL, PRIMARY KEY (board_id, attachment_type_id), CONSTRAINT FK_D12700A6E7EC5785 FOREIGN KEY (board_id) REFERENCES boards (id) NOT DEFERRABLE INITIALLY IMMEDIATE, CONSTRAINT FK_D12700A6DD9D915 FOREIGN KEY (attachment_type_id) REFERENCES attachment_types (id) NOT DEFERRABLE INITIALLY IMMEDIATE);
CREATE INDEX IDX_D12700A6E7EC5785 ON boards_attachment_types (board_id);
CREATE INDEX IDX_D12700A6DD9D915 ON boards_attachment_types (attachment_type_id);
CREATE TABLE attachment_types (id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL, extension VARCHAR(255) NOT NULL, mime_type VARCHAR(255) NOT NULL, description VARCHAR(255) NOT NULL, is_image BOOLEAN NOT NULL, is_video BOOLEAN NOT NULL, is_audio BOOLEAN NOT NULL);
CREATE UNIQUE INDEX UNIQ_EFAED7199FB73D77 ON attachment_types (extension);
CREATE TABLE users (id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL, username VARCHAR(255) NOT NULL, password VARCHAR(255) NOT NULL, created_at DATETIME NOT NULL, last_logged_in_at DATETIME NOT NULL, failed_logins INTEGER NOT NULL, last_failed_login_at DATETIME NOT NULL);
CREATE UNIQUE INDEX UNIQ_1483A5E9F85E0677 ON users (username);
